// all five criteria must pass before the submit button becomes active
const passwordValidation = computed(() => {
  const pwd = signupForm.value.password
  return {
    length: pwd.length >= 8 && pwd.length <= 30,
    uppercase: /[A-Z]/.test(pwd),
    lowercase: /[a-z]/.test(pwd),
    number: /[0-9]/.test(pwd),
    special: /[!@#$%^&*(),.?":{}|<>]/.test(pwd)
  }
})

const isPasswordValid = computed(() => {
  return Object.values(passwordValidation.value).every(v => v === true)
})

async function handleLogin() {
  loginError.value = '' // clear the old error immediately so it doesn't linger
  loginLoading.value = true
  try {
    const ok = await login(loginForm.value.email, loginForm.value.password)
    if (ok) {
      router.push('/dashboard')
    } else {
      loginError.value = authError.value || 'Login failed'
    }
  } finally {
    loginLoading.value = false
  }
}

function isValidEmail(email) {
  const atIndex = email.indexOf('@')
  return atIndex > 0 && atIndex < email.length - 1
}

// validate locally first so the user gets instant feedback before we hit the API
async function handleSignup() {
  signupError.value = ''
  signupSuccess.value = ''
  if (!isValidEmail(signupForm.value.email)) {
    signupError.value = 'Please enter a valid email address'
    return
  }
  if (!isPasswordValid.value) {
    signupError.value = 'Please meet all password requirements'
    return
  }
  signupLoading.value = true
  try {
    const ok = await register(
      signupForm.value.email,
      signupForm.value.name,
      signupForm.value.password
    )
    if (ok) {
      router.push(`/verify-email?email=${encodeURIComponent(signupForm.value.email)}`)
    } else {
      signupError.value = authError.value || 'Registration failed'
    }
  } finally {
    signupLoading.value = false
  }
}

